// ── CLOCK ─────────────────────────────────────────────────────
function tick(){ document.getElementById('clock').textContent = new Date().toLocaleTimeString('id-ID',{hour:'2-digit',minute:'2-digit',second:'2-digit'}); }
tick(); setInterval(tick,1000);

// ── HELPERS ───────────────────────────────────────────────────
const fmt  = n => Number(n||0).toLocaleString('id-ID');
const fmtd = n => Number(n||0).toFixed(1);
const sum  = (arr,fn) => arr.reduce((a,b)=>a+(fn?fn(b):(b||0)),0);
function setShift(el,s){ document.querySelectorAll('.stab').forEach(t=>t.classList.remove('on')); el.classList.add('on'); activeShift=s; render(); }

function getGate(){
  const tgl = document.getElementById('datePicker').value;
  const bln = document.getElementById('bulanPick').value;
  return GATE.filter(d=>{
    if(tgl && d.date!==tgl) return false;
    if(bln && !d.date.startsWith('2026-'+bln)) return false;
    if(activeShift!=='ALL' && d.shift!==activeShift) return false;
    return true;
  });
}

function deltaArrow(v){ return v>0?`<span class="up">▲ ${fmt(v)}</span>`:v<0?`<span class="dn">▼ ${fmt(Math.abs(v))}</span>`:`<span>— ${fmt(v)}</span>`; }

// ── BLOCK ACTIVITY HELPERS ────────────────────────────────────
function baGetD(blk){
  return baShift==='ALL' ? (BTD[blk]||null) : (BSD[blk]?.[baShift]||null);
}
function baTot(d){
  if(!d) return 0;
  return (d.delivery||0)+(d.loading||0)+(d.receiving||0)+(d.discharge||0)+(d.shifting||0);
}
function baLvlOf(v,th){
  if(v<=0) return null;
  if(v<th[0]) return {lbl:'Rendah',  bg:'#dcfce7',cl:'#15803d'};
  if(v<th[1]) return {lbl:'Sedang',  bg:'#dbeafe',cl:'#1d4ed8'};
  if(v<th[2]) return {lbl:'Tinggi',  bg:'#fef3c7',cl:'#b45309'};
  return               {lbl:'Sangat Tinggi',bg:'#fee2e2',cl:'#b91c1c'};
}
function baHexRgb(h){const n=parseInt(h.slice(1),16);return[n>>16&255,(n>>8)&255,n&255];}
function baMixHex(a,b,t){
  const ca=baHexRgb(a),cb=baHexRgb(b);
  return `rgb(${Math.round(ca[0]+(cb[0]-ca[0])*t)},${Math.round(ca[1]+(cb[1]-ca[1])*t)},${Math.round(ca[2]+(cb[2]-ca[2])*t)})`;
}
const BA_STOPS=['#16a34a','#facc15','#f97316','#dc2626'];
function baActColor(t){
  const s=BA_STOPS.length-1,sT=Math.min(t,1)*s,i=Math.min(Math.floor(sT),s-1);
  return baMixHex(BA_STOPS[i],BA_STOPS[i+1],sT-i);
}
const baDash = n => n>0 ? fmt(n) : '—';

// ── RENDER ────────────────────────────────────────────────────
function render(){
  const gate = getGate();
  const view = document.getElementById('viewMode').value;
  const bln  = document.getElementById('bulanPick').value;
  const tgl  = document.getElementById('datePicker').value;

  const expIn=sum(gate,d=>d.exp_in), expOut=sum(gate,d=>d.exp_out);
  const impIn=sum(gate,d=>d.imp_in), impOut=sum(gate,d=>d.imp_out);
  const domIn=sum(gate,d=>d.dom_in), domOut=sum(gate,d=>d.dom_out);

  renderAlerts(gate);

  const mc = document.getElementById('mainContent');
  mc.innerHTML = '';

  if(view==='gate'||view==='both') mc.appendChild(buildGateSection(gate,expIn,expOut,impIn,impOut,domIn,domOut));
  if(view==='cy'||view==='both'){
    mc.appendChild(buildCYSection());
    const blkSec = buildBlockActivitySection();
    blkSec.id = 'blockActivitySection';
    mc.appendChild(blkSec);
    const hmSec = buildBlockHeatmapSection();
    hmSec.id = 'blockHeatmapSection';
    mc.appendChild(hmSec);
  }
  if(view==='gate'||view==='both'){ mc.appendChild(buildChartSection(gate,bln)); mc.appendChild(buildTableSection(gate)); }

  setTimeout(()=>{
    if(view!=='cy') drawTrenChart(gate,bln||tgl);
    if(view!=='cy') drawPieChart(expIn,impIn,domIn);
    if(view!=='gate') drawCYChart();
    if(view!=='gate') drawDailyTrendChart();
  },50);

  document.getElementById('updInfo').textContent = `${gate.length} record · Diperbarui ${new Date().toLocaleTimeString('id-ID')}`;
}

// ── ALERTS ────────────────────────────────────────────────────
function renderAlerts(gate){
  const bar = document.getElementById('alertBar');
  const alerts = [];
  if(!gate.length){ bar.innerHTML='<div class="al al-a"><div class="al-dot"></div>Tidak ada data untuk filter ini</div>'; return; }
  const expIn=sum(gate,d=>d.exp_in), expOut=sum(gate,d=>d.exp_out);
  const impIn=sum(gate,d=>d.imp_in), impOut=sum(gate,d=>d.imp_out);
  const domIn=sum(gate,d=>d.dom_in), domOut=sum(gate,d=>d.dom_out);
  const totalIn=expIn+impIn+domIn, totalOut=expOut+impOut+domOut;
  const delta=totalIn-totalOut;
  if(delta>500) alerts.push({c:'al-a',t:`⚠ Akumulasi IN melebihi OUT sebesar ${fmt(delta)} box`});
  if(expIn>impIn*1.5) alerts.push({c:'al-b',t:`📦 Ekspor dominan: ${fmt(expIn)} vs Impor ${fmt(impIn)} box`});
  if(gate.length>0) alerts.push({c:'al-g',t:`✓ ${gate.length} shift dianalisis · Total gate: ${fmt(totalIn+totalOut)} box`});
  const cyToday = CY.find(c=>c.date===document.getElementById('datePicker').value);
  if(cyToday && cyToday.avg_mph<18) alerts.push({c:'al-a',t:`⚠ MPH rata-rata rendah: ${cyToday.avg_mph} box/jam`});
  bar.innerHTML = alerts.map(a=>`<div class="al ${a.c}"><div class="al-dot"></div>${a.t}</div>`).join('');
}

