// ── CHARTS ────────────────────────────────────────────────────
function drawTrenChart(gate,bln){
  const byDate={};
  gate.forEach(d=>{ if(!byDate[d.date]) byDate[d.date]={in:0,out:0}; byDate[d.date].in+=d.exp_in+d.imp_in+d.dom_in; byDate[d.date].out+=d.exp_out+d.imp_out+d.dom_out; });
  const labels=Object.keys(byDate).sort().slice(-31);
  const dataIn=labels.map(l=>byDate[l].in), dataOut=labels.map(l=>byDate[l].out);
  const el=document.getElementById('chartTren'); if(!el) return;
  if(chartTren) chartTren.destroy();
  chartTren=new Chart(el,{type:'line',data:{labels:labels.map(l=>l.slice(5)),datasets:[
    {label:'Total IN',data:dataIn,borderColor:'#2563a8',backgroundColor:'rgba(37,99,168,.1)',tension:.35,fill:true,pointRadius:2,borderWidth:2},
    {label:'Total OUT',data:dataOut,borderColor:'#b91c1c',backgroundColor:'rgba(185,28,28,.06)',tension:.35,fill:true,pointRadius:2,borderWidth:2}
  ]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{position:'top',labels:{font:{size:10},boxWidth:10}}},scales:{x:{ticks:{font:{size:9},maxRotation:45}},y:{ticks:{font:{size:9}},grid:{color:'#f3f4f6'}}}}});
}

