// ── BLOCK ACTIVITY SECTION — NEW (from RTG_Activity_28052026) ─
// ══════════════════════════════════════════════════════════════
function buildBlockActivitySection(){
  const el = document.createElement('div');

  // ── summary stats ──
  let tM=0,tD=0,tL=0,tR=0,tDis=0,tS=0,blkA=0,rtgSet=new Set();
  for(const blk of Object.keys(BTD)){
    const d=baGetD(blk); if(!d||baTot(d)===0) continue;
    blkA++; tM+=baTot(d); tD+=d.delivery||0; tL+=d.loading||0; tR+=d.receiving||0; tDis+=d.discharge||0; tS+=d.shifting||0;
    (d.rtgs||[]).forEach(r=>rtgSet.add(r));
  }
  const rtgC=[...rtgSet].filter(r=>r.startsWith('R')).length;
  const rsC =[...rtgSet].filter(r=>r.startsWith('S')).length;

  // ── top blok ──
  let mb='',mt=0;
  for(const b of Object.keys(BTD)){const t=baTot(baGetD(b));if(t>mt){mt=t;mb=b;}}

  // ── shift label ──
  const shiftLabels={ALL:'Semua Shift',I:'Shift I · 08:00–16:00',II:'Shift II · 16:00–00:00',III:'Shift III · 00:00–08:00'};
  const shiftBg={ALL:'linear-gradient(135deg,#1e293b,#334155)',I:'linear-gradient(135deg,#1e3a8a,#2563eb)',II:'linear-gradient(135deg,#78350f,#d97706)',III:'linear-gradient(135deg,#14532d,#16a34a)'};

  // ── build zone cards ──
  function buildZoneCard(zone){
    const ab = zone.bloks.filter(b=>BTD[b]&&baTot(baGetD(b))>0);
    let zM=0,zD=0,zL=0,zR=0,zDis=0,zS=0,rtgSet2=new Set();
    for(const b of ab){
      const d=baGetD(b); if(!d) continue;
      zM+=baTot(d); zD+=d.delivery||0; zL+=d.loading||0; zR+=d.receiving||0; zDis+=d.discharge||0; zS+=d.shifting||0;
      (d.rtgs||[]).forEach(r=>rtgSet2.add(r));
    }
    const rtgArr=[...rtgSet2].filter(r=>r.startsWith('R')).sort();
    const rsArr =[...rtgSet2].filter(r=>r.startsWith('S')).sort();
    const chips=[
      ...rtgArr.map(r=>`<span class="ba-chip ba-chip-rtg">${r}</span>`),
      ...rsArr.map(r=>`<span class="ba-chip ba-chip-rs">${r}</span>`)
    ].join('');

    const zoneMax = Math.max(...ab.map(b=>baTot(baGetD(b))),1);
    const rows = ab.length
      ? ab.map(b=>{
          const d=baGetD(b); if(!d) return '';
          const t=baTot(d);
          const ratio=t/zoneMax;
          const tBg=t>0?baActColor(ratio):'#f1f5f9';
          const tCl=t>0?(ratio>0.45?'#fff':'#1f2937'):'#94a3b8';
          return `<tr>
            <td class="ba-td-blk">${b}</td>
            <td class="ba-td-r" style="color:#b45309">${baDash(d.delivery)}</td>
            <td class="ba-td-r" style="color:#1e40af">${baDash(d.loading)}</td>
            <td class="ba-td-r" style="color:#15803d">${baDash(d.receiving)}</td>
            <td class="ba-td-r" style="color:#6d28d9">${baDash(d.discharge)}</td>
            <td class="ba-td-r" style="color:#374151">${baDash(d.shifting)}</td>
            <td class="ba-td-tot"><span class="ba-tot-chip" style="background:${tBg};color:${tCl}">${fmt(t)}</span></td>
          </tr>`;
        }).join('')
      : `<tr><td colspan="7" style="padding:8px;color:var(--text3);font-style:italic;font-size:10px;text-align:center">Tidak ada aktivitas</td></tr>`;

    const footer = ab.length ? `<tfoot><tr>
      <td class="ba-td-blk" style="font-size:9px;font-weight:700;color:var(--text3)">TOTAL</td>
      <td class="ba-td-r" style="color:#b45309;font-weight:800">${fmt(zD)}</td>
      <td class="ba-td-r" style="color:#1e40af;font-weight:800">${fmt(zL)}</td>
      <td class="ba-td-r" style="color:#15803d;font-weight:800">${fmt(zR)}</td>
      <td class="ba-td-r" style="color:#6d28d9;font-weight:800">${fmt(zDis)}</td>
      <td class="ba-td-r" style="font-weight:800">${fmt(zS)}</td>
      <td class="ba-td-r" style="font-weight:900">${fmt(zM)}</td>
    </tr></tfoot>` : '';

    const alatRow = ab.length ? `<div class="ba-alat-row"><span class="ba-alat-lbl">Alat:</span>${chips}</div>` : '';

    return `<div class="ba-zone-card">
      <div class="ba-zone-hdr" style="background:${zone.bg}">
        <div class="ba-zone-hdr-left">${zone.icon} ${zone.label}</div>
        <div class="ba-zone-hdr-right">
          <span class="ba-zbadge">${ab.length} Blok</span>
          <span class="ba-zbadge">${fmt(zM)} Moves</span>
        </div>
      </div>
      <table class="ba-zt">
        <thead><tr>
          <th class="ba-th-l">Blok</th>
          <th class="ba-th-r" style="color:#b45309">Deliv</th>
          <th class="ba-th-r" style="color:#1e40af">Load</th>
          <th class="ba-th-r" style="color:#15803d">Recv</th>
          <th class="ba-th-r" style="color:#6d28d9">Disc</th>
          <th class="ba-th-r">Shift</th>
          <th class="ba-th-r">Total</th>
        </tr></thead>
        <tbody>${rows}</tbody>
        ${footer}
      </table>
      ${alatRow}
    </div>`;
  }

  el.innerHTML = `
  <div class="sec-hdr">Block Activity — 28 Mei 2026 · Aktivitas per Zona</div>

  <style>
    .ba-shift-tabs{display:flex;gap:5px;margin-bottom:10px;align-items:center}
    .ba-stab{cursor:pointer;padding:5px 14px;border-radius:7px;font-size:11px;font-weight:700;border:1.5px solid var(--border2);background:var(--white);color:var(--text2);transition:.12s;user-select:none}
    .ba-stab:hover{border-color:var(--blue2);color:var(--blue2)}
    .ba-stab.on-ALL{background:linear-gradient(135deg,#1e293b,#334155);color:#fff;border-color:transparent}
    .ba-stab.on-I  {background:linear-gradient(135deg,#1e3a8a,#2563eb);color:#fff;border-color:transparent}
    .ba-stab.on-II {background:linear-gradient(135deg,#78350f,#d97706);color:#fff;border-color:transparent}
    .ba-stab.on-III{background:linear-gradient(135deg,#14532d,#16a34a);color:#fff;border-color:transparent}

    .ba-sum-bar{background:linear-gradient(135deg,#1e293b,#334155);border-radius:9px;padding:8px 18px;display:flex;margin-bottom:12px;box-shadow:0 2px 6px rgba(0,0,0,.15)}
    .ba-sum-item{color:#fff;text-align:center;flex:1;padding:2px 6px}
    .ba-sum-val{font-size:17px;font-weight:900;font-family:monospace;display:block}
    .ba-sum-lbl{font-size:8px;opacity:.55;text-transform:uppercase;letter-spacing:.05em;margin-top:1px;display:block}
    .ba-sum-div{width:1px;background:rgba(255,255,255,.15);margin:4px 0}

    .ba-zone-row{display:grid;grid-template-columns:repeat(auto-fit,minmax(300px,1fr));gap:12px;margin-bottom:14px;align-items:start}
    .ba-zone-stack{display:flex;flex-direction:column;gap:12px}
    .ba-zone-card{background:var(--white);border-radius:10px;overflow:hidden;box-shadow:var(--shadow);transition:box-shadow .15s}
    .ba-zone-card:hover{box-shadow:0 4px 16px rgba(0,0,0,.12)}
    .ba-zone-hdr{padding:9px 14px;display:flex;align-items:center;justify-content:space-between;gap:6px}
    .ba-zone-hdr-left{display:flex;align-items:center;gap:6px;color:#fff;font-size:13px;font-weight:800}
    .ba-zone-hdr-right{display:flex;gap:4px;flex-shrink:0}
    .ba-zbadge{background:rgba(255,255,255,.22);color:#fff;padding:2px 8px;border-radius:10px;font-size:10px;font-weight:700;white-space:nowrap}

    .ba-zt{width:100%;border-collapse:collapse}
    .ba-zt thead tr{background:var(--gray-ll)}
    .ba-th-l{padding:4px 8px;font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.04em;color:var(--text3);border-bottom:1.5px solid var(--border);text-align:left;white-space:nowrap}
    .ba-th-r{padding:4px 8px;font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.04em;color:var(--text3);border-bottom:1.5px solid var(--border);text-align:right;white-space:nowrap}
    .ba-td-blk{padding:4px 10px;font-size:13px;font-weight:800;color:var(--navy);text-align:left;border-bottom:1px solid #f3f6f9}
    .ba-td-r{padding:4px 8px;font-size:11px;font-family:monospace;text-align:right;border-bottom:1px solid #f3f6f9}
    .ba-td-tot{padding:4px 8px 4px 4px;text-align:right;border-bottom:1px solid #f3f6f9}
    .ba-tot-chip{display:inline-block;min-width:42px;padding:2px 8px;border-radius:6px;font-size:11px;font-weight:900;font-family:monospace}
    .ba-zt tbody tr:nth-child(even){background:var(--gray-l)}
    .ba-zt tbody tr:hover{background:#eef4ff}
    .ba-zt tfoot td{background:var(--gray-ll);border-top:1.5px solid var(--border2)}
    .ba-alat-row{padding:5px 10px 7px;border-top:1px solid var(--border);background:var(--gray-l);display:flex;flex-wrap:wrap;gap:3px;align-items:center}
    .ba-alat-lbl{font-size:9px;color:var(--text3);font-weight:600;margin-right:3px}
    .ba-chip{display:inline-block;padding:1px 5px;border-radius:4px;font-size:9px;font-weight:700;font-family:monospace}
    .ba-chip-rtg{background:#dbeafe;color:#1e40af;border:1px solid #bfdbfe}
    .ba-chip-rs {background:#ccfbf1;color:#0f766e;border:1px solid #99f6e4}
  </style>

  <div class="ba-shift-tabs">
    <div class="ba-stab on-ALL" onclick="setBaShift('ALL',this)">Semua Shift</div>
    <div class="ba-stab" onclick="setBaShift('I',this)">Shift I<span style="font-size:9px;opacity:.72;margin-left:3px">08–16</span></div>
    <div class="ba-stab" onclick="setBaShift('II',this)">Shift II<span style="font-size:9px;opacity:.72;margin-left:3px">16–00</span></div>
    <div class="ba-stab" onclick="setBaShift('III',this)">Shift III<span style="font-size:9px;opacity:.72;margin-left:3px">00–08</span></div>
    <div style="margin-left:auto;font-size:10px;color:var(--text3)">${shiftLabels[baShift]}</div>
  </div>

  <div class="ba-sum-bar">
    <div class="ba-sum-item"><span class="ba-sum-val">${fmt(tM)}</span><span class="ba-sum-lbl">Total Moves</span></div>
    <div class="ba-sum-div"></div>
    <div class="ba-sum-item"><span class="ba-sum-val" style="color:#93c5fd">${mb}</span><span class="ba-sum-lbl">Blok Terbanyak</span></div>
    <div class="ba-sum-div"></div>
    <div class="ba-sum-item"><span class="ba-sum-val" style="color:#86efac">${fmt(mt)}</span><span class="ba-sum-lbl">Moves (top blok)</span></div>
    <div class="ba-sum-div"></div>
    <div class="ba-sum-item"><span class="ba-sum-val" style="color:#fde68a">${fmt(tD)}</span><span class="ba-sum-lbl">Delivery</span></div>
    <div class="ba-sum-div"></div>
    <div class="ba-sum-item"><span class="ba-sum-val" style="color:#93c5fd">${fmt(tL)}</span><span class="ba-sum-lbl">Loading</span></div>
    <div class="ba-sum-div"></div>
    <div class="ba-sum-item" style="margin-left:auto"><span class="ba-sum-val" style="color:#e2e8f0">28/05/2026</span><span class="ba-sum-lbl">${shiftLabels[baShift]}</span></div>
  </div>

  <div class="ba-zone-row">
    ${BA_ZONES.filter(z=>!z.stack).map(z=>buildZoneCard(z)).join('')}
    <div class="ba-zone-stack">${BA_ZONES.filter(z=>z.stack).map(z=>buildZoneCard(z)).join('')}</div>
  </div>`;

  return el;
}

function setBaShift(s, el){
  baShift = s;
  document.querySelectorAll('.ba-stab').forEach(t=>{ t.className='ba-stab'; });
  el.className = 'ba-stab on-'+s;
  const sec = document.getElementById('blockActivitySection');
  if(sec){ const n=buildBlockActivitySection(); n.id='blockActivitySection'; sec.replaceWith(n); }
  // restore active tab class after rebuild
  setTimeout(()=>{
    document.querySelectorAll('.ba-stab').forEach(t=>{
      if((t.textContent||'').startsWith(s==='ALL'?'Semua':('Shift '+s))) t.className='ba-stab on-'+s;
    });
  },10);
}

// ══════════════════════════════════════════════════════════════
// ── BLOCK HEATMAP SECTION — NEW ───────────────────────────────
// ══════════════════════════════════════════════════════════════
let hmShift = 'ALL';

function buildBlockHeatmapSection(){
  const el = document.createElement('div');

  const sBg={ALL:'#374151',I:'#1d4ed8',II:'#b45309',III:'#15803d'};

  function buildHmZone(zone){
    const ab = zone.bloks.filter(b=>BTD[b]);
    if(!ab.length) return '';
    let zM=0;
    const items = ab.map(blk=>{ const d=hmGetD(blk); const t=d?baTot(d):0; zM+=t; return {blk,t,d}; });
    const maxZ = Math.max(...items.map(c=>c.t),1);
    const cells = items.map(({blk,t,d})=>{
      const r=t/maxZ;
      const bg=t?baActColor(r):'#f1f5f9';
      const cl=t===0?'#94a3b8':(r>0.45?'#fff':'#1f2937');
      const lv=baLvlOf(t,zone.th);
      return `<div class="hm3-cell" style="background:${bg};color:${cl}"
        title="Blok ${blk} · D:${d?.delivery||0} L:${d?.loading||0} R:${d?.receiving||0} Dis:${d?.discharge||0} Sh:${d?.shifting||0} = ${t}">
        <span class="hm3-cell-blk">${blk}</span>
        <span class="hm3-cell-val">${t||'—'}</span>
        ${lv?`<span class="hm3-cell-lvl">${lv.lbl}</span>`:''}
      </div>`;
    }).join('');
    return `<div class="hm3-zone" style="--zone:${zone.color}">
      <div class="hm3-zone-hdr">
        <span class="hm3-zone-name"><span class="hm3-dot" style="background:${zone.color}"></span>${zone.label}</span>
        <span class="hm3-zone-meta">${ab.length} blok · ${fmt(zM)} moves</span>
      </div>
      <div class="hm3-cells">${cells}</div>
    </div>`;
  }

  // ranking (semua blok aktif, urut terbesar)
  function blkZoneTh(b){ for(const z of HM_ZONES) if(z.bloks.includes(b)) return z.th; return [40,150,280]; }
  const ranked = Object.keys(BTD)
    .map(b=>({b,t:baTot(hmGetD(b))}))
    .filter(x=>x.t>0)
    .sort((a,b)=>b.t-a.t);
  const mx = ranked[0]?.t||1;
  const rankHtml = ranked.map(({b,t},i)=>{
    const r=t/mx; const lv=baLvlOf(t,blkZoneTh(b));
    return `<div class="hm3-rank-row">
      <div class="hm3-rank-num">${i+1}</div>
      <div class="hm3-rank-blk">${b}</div>
      <div class="hm3-rank-bar"><i style="width:${Math.round(r*100)}%;background:${baActColor(r)}"></i></div>
      <div class="hm3-rank-val">${fmt(t)}</div>
      ${lv?`<div class="hm3-rank-lvl" style="background:${lv.bg};color:${lv.cl}">${lv.lbl}</div>`:'<div class="hm3-rank-lvl"></div>'}
    </div>`;
  }).join('');

  el.innerHTML = `
  <div class="sec-hdr" style="margin-top:4px">Block Yard Activity Map — Tingkat Aktivitas RTG per Blok · 28 Mei 2026</div>

  <style>
    .hm3-controls{display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:8px;margin-bottom:8px}
    .hm3-seg{display:flex;gap:4px}
    .hm3-seg-btn{padding:5px 12px;border-radius:6px;font-size:11px;font-weight:700;border:1.5px solid var(--border2);background:var(--white);color:var(--text2);cursor:pointer;transition:.12s}
    .hm3-seg-btn.on{background:var(--c);color:#fff;border-color:transparent;box-shadow:0 1px 4px rgba(0,0,0,.15)}
    .hm3-legend-bar{width:130px;height:7px;border-radius:4px;background:linear-gradient(to right,#16a34a,#facc15,#f97316,#dc2626)}
    .hm3-legend-labels{display:flex;justify-content:space-between;width:130px;font-size:8px;color:var(--text3);font-weight:700;margin-top:2px}

    .hm3-zone-grid{display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:10px}
    .hm3-zone{background:var(--white);border:1px solid var(--border);border-left:4px solid var(--zone);border-radius:9px;box-shadow:var(--shadow);padding:9px 11px}
    .hm3-zone-hdr{display:flex;align-items:center;justify-content:space-between;margin-bottom:7px;flex-wrap:wrap;gap:4px}
    .hm3-zone-name{display:flex;align-items:center;gap:5px;font-size:11px;font-weight:800;color:var(--text2);text-transform:uppercase;letter-spacing:.05em}
    .hm3-dot{width:7px;height:7px;border-radius:50%;flex-shrink:0;display:inline-block}
    .hm3-zone-meta{font-size:10px;font-weight:700;color:var(--text3)}
    .hm3-cells{display:flex;flex-wrap:wrap;gap:5px}
    .hm3-cell{border-radius:7px;padding:6px 4px;text-align:center;flex:1 1 70px;min-width:70px;transition:transform .1s}
    .hm3-cell:hover{transform:scale(1.06);z-index:3;box-shadow:0 2px 8px rgba(0,0,0,.2)}
    .hm3-cell-blk{font-size:10px;font-weight:800;font-family:var(--mono);display:block;opacity:.92}
    .hm3-cell-val{font-size:17px;font-weight:900;font-family:var(--mono);display:block;line-height:1.1;margin:1px 0}
    .hm3-cell-lvl{font-size:8px;font-weight:800;text-transform:uppercase;letter-spacing:.02em;opacity:.95;display:block}

    .hm3-rank-card{background:var(--white);border-radius:var(--r2);box-shadow:var(--shadow);padding:10px 14px}
    .hm3-rank-title{font-size:10px;font-weight:800;color:var(--text3);text-transform:uppercase;letter-spacing:.06em;margin-bottom:7px}
    .hm3-rank-row{display:flex;align-items:center;gap:8px;padding:2px 0}
    .hm3-rank-num{width:16px;font-size:9px;font-weight:700;color:var(--text3);text-align:right;flex-shrink:0}
    .hm3-rank-blk{width:30px;font-size:11px;font-weight:900;font-family:var(--mono);color:var(--navy);flex-shrink:0}
    .hm3-rank-bar{flex:1;height:12px;background:var(--gray-ll);border-radius:4px;overflow:hidden}
    .hm3-rank-bar i{display:block;height:100%;border-radius:4px}
    .hm3-rank-val{width:50px;text-align:right;font-size:10px;font-weight:800;font-family:var(--mono);flex-shrink:0}
    .hm3-rank-lvl{width:70px;text-align:right;font-size:9px;font-weight:700;flex-shrink:0}
  </style>

  <div class="hm3-controls">
    <div class="hm3-seg">
      ${['ALL','I','II','III'].map(s=>`<button class="hm3-seg-btn${hmShift===s?' on':''}" style="--c:${sBg[s]}" onclick="setHmShift('${s}')">${s==='ALL'?'Semua':'Shift '+s}</button>`).join('')}
    </div>
    <div>
      <div class="hm3-legend-bar"></div>
      <div class="hm3-legend-labels"><span>Rendah</span><span>Sedang</span><span>Tinggi</span><span>Sangat Tinggi</span></div>
    </div>
  </div>

  <div class="hm3-zone-grid">
    ${HM_ZONES.map(z=>buildHmZone(z)).join('')}
  </div>

  <div class="hm3-rank-card">
    <div class="hm3-rank-title">🏆 Ranking Blok Aktivitas RTG Tertinggi ${hmShift==='ALL'?'(Semua Shift)':'(Shift '+hmShift+')'}</div>
    ${rankHtml}
  </div>`;

  return el;
}

function hmGetD(blk){
  return hmShift==='ALL' ? (BTD[blk]||null) : (BSD[blk]?.[hmShift]||null);
}

function setHmShift(s){
  hmShift = s;
  const sec = document.getElementById('blockHeatmapSection');
  if(sec){ const n=buildBlockHeatmapSection(); n.id='blockHeatmapSection'; sec.replaceWith(n); }
}

// ── INIT ──────────────────────────────────────────────────────
document.getElementById('datePicker').value='';
render();